import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Button, Image } from 'decantr/components';

code.example:
function ProductGrid() {
  const { div, span, h3 } = tags;
  const products = [
    { image: '/images/product-1.jpg', name: 'Wireless Headphones', badge: 'New', description: 'Premium noise-cancelling headphones.', price: 199.99 },
    { image: '/images/product-2.jpg', name: 'Mechanical Keyboard', badge: null, description: 'RGB backlit mechanical keyboard.', price: 149.99 },
    { image: '/images/product-3.jpg', name: 'USB-C Hub', badge: 'Sale', description: '7-in-1 USB-C hub with HDMI output.', price: 49.99 },
    { image: '/images/product-4.jpg', name: 'Monitor Stand', badge: null, description: 'Adjustable aluminum monitor stand.', price: 79.99 }
  ];

  return div({ class: css('_grid _gcaf280 _gap4 _p4') },
    ...products.map(p =>
      Card({},
        Image({ src: p.image, alt: p.name, class: css('_wfull _h[200px] _object[cover]') }),
        Card.Body({ class: css('_flex _col _gap2') },
          div({ class: css('_flex _aic _jcsb') },
            h3({ class: css('_heading5') }, p.name),
            p.badge ? Badge({ variant: 'accent' }, p.badge) : null
          ),
          span({ class: css('_fgmuted _textsm') }, p.description),
          div({ class: css('_flex _aic _jcsb _mt2') },
            span({ class: css('_heading4') }, `$${p.price}`),
            Button({ variant: 'primary', size: 'sm' }, 'Add to Cart')
          )
        )
      )
    )
  );
}
